const HLS_CDN = "https://cdn.jsdelivr.net/npm/hls.js@1.5.20/+esm";

let hlsPromise = null;

export const getHls = async () => {
  if (globalThis.Hls) {
    return globalThis.Hls;
  }

  if (!hlsPromise) {
    hlsPromise = import(HLS_CDN)
      .then((module) => module.default || module.Hls || module)
      .catch((error) => {
        console.error("Không tải được HLS.js từ CDN", error);
        throw error;
      });
  }

  return hlsPromise;
};

export default getHls;
